//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Structured document tags (SDT): properties, content levels, typed sub-tags".
//!
//! Each `#[test]` encodes a Word-compliance constraint mined from the OOXML /
//! Word reference (ISO 29500-1 §17.5.2, the normative wml.xsd schema, and the
//! MS-OI29500 implementer notes). A FAILING assertion here is a REAL
//! Word-compliance gap in the stemma engine — it means stemma diverges from how
//! Microsoft Word reads or preserves the markup. Do NOT weaken a failing
//! assertion to make it pass; a fail is the finding.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED content
//! byte-verbatim. So `reserialize()` of an unedited document reflects stemma's
//! verbatim-preservation contract, not Word's render-time normalization.
//! Therefore the `xml*` assertions below only target markup the serializer
//! ACTIVELY preserves/re-emits (opaque SDT wrappers, structural re-wrapping,
//! Annex A ordering) — never "Word ignores value V on layout".

use std::io::{Cursor, Read, Write};

use stemma::api::Document;
use stemma::{DocxRuntime, ExportMode, ExportOptions, SimpleRuntime, TransactionMeta};

// ─── Prelude / plumbing ──────────────────────────────────────────────────────

/// Build a valid minimal `.docx` from a `document.xml` body fragment.
///
/// `body_xml` is wrapped in `<w:document …><w:body>…</w:body></w:document>`.
/// `extra_parts` is a list of `(part_path, xml)` (e.g.
/// `("word/styles.xml", "<w:styles…/>")`); each gets a `[Content_Types].xml`
/// override and is written into the zip. (None of the specs below need extra
/// parts, but the signature matches the workflow contract.)
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides for any extra parts.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (path, _) in extra_parts {
        let content_type = content_type_for(path);
        overrides.push_str(&format!(
            r#"<Override PartName="/{path}" ContentType="{content_type}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // document.xml.rels: add a typed rel for any known extra part (styles, etc.).
    let mut doc_rels_body = String::new();
    for (i, (path, _)) in extra_parts.iter().enumerate() {
        if let Some(rel_type) = rel_type_for(path) {
            let target = path.strip_prefix("word/").unwrap_or(path);
            doc_rels_body.push_str(&format!(
                r#"<Relationship Id="rIdX{i}" Type="{rel_type}" Target="{target}"/>"#
            ));
        }
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rels_body}</Relationships>"#
    );

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(Cursor::new(&mut buf));
        let opts: zip::write::FileOptions = zip::write::FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (path, xml) in extra_parts {
            zip.start_file(*path, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

fn content_type_for(path: &str) -> &'static str {
    match path {
        "word/styles.xml" => {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        }
        "word/numbering.xml" => {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        }
        _ => "application/xml",
    }
}

fn rel_type_for(path: &str) -> Option<&'static str> {
    match path {
        "word/styles.xml" => {
            Some("http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles")
        }
        "word/numbering.xml" => {
            Some("http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering")
        }
        _ => None,
    }
}

/// Unzip and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(Cursor::new(docx)).expect("open docx zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse then re-serialize, returning the resulting `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&ExportOptions::default())
        .expect("serialize for reserialize");
    document_xml_of(&out)
}

/// `opensClean`: stemma's package validator reports no errors for these bytes.
fn assert_opens_clean(bytes: &[u8], msg: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{msg} — validate() reported issues: ok={}, issues={:?}",
        report.ok,
        report.issues
    );
}

/// Whitespace-normalized ordered-fragment check used to emulate the `xmlRegex`
/// expectations. The reference regexes are all of the form "fragment A, then
/// (optional whitespace / wildcard), then fragment B, …". We translate each
/// regex into a sequence of literal fragments (the stable parts between `\s*`,
/// `.*`, and `[^>]*` boundaries) and assert they appear IN ORDER in the document
/// XML after collapsing inter-tag whitespace. This is a faithful rendering of the
/// regex intent without pulling in the `regex` crate (not a dev-dependency here).
fn assert_xml_ordered(xml: &str, fragments: &[&str], msg: &str) {
    let normalized = collapse_inter_tag_whitespace(xml);
    let mut search_from = 0usize;
    for frag in fragments {
        match normalized[search_from..].find(frag) {
            Some(rel) => {
                search_from += rel + frag.len();
            }
            None => panic!(
                "{msg} — expected XML to contain (in order) the fragments {fragments:?}; \
                 fragment {frag:?} not found after offset {search_from}.\nNormalized XML:\n{normalized}"
            ),
        }
    }
}

/// Collapse runs of whitespace that sit entirely between `>` and `<` so that
/// formatting differences (newlines/indentation the serializer may or may not
/// emit) don't defeat an ordered-fragment match.
fn collapse_inter_tag_whitespace(xml: &str) -> String {
    let mut out = String::with_capacity(xml.len());
    let bytes = xml.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        let c = bytes[i] as char;
        if c.is_ascii_whitespace() {
            let prev = out.chars().last();
            let mut j = i;
            while j < bytes.len() && (bytes[j] as char).is_ascii_whitespace() {
                j += 1;
            }
            let next = if j < bytes.len() {
                Some(bytes[j] as char)
            } else {
                None
            };
            if prev == Some('>') && next == Some('<') {
                i = j;
                continue;
            }
            out.push(' ');
            i = j;
            continue;
        }
        out.push(c);
        i += 1;
    }
    out
}

