#[test]
fn cell_level_sdt_wrapping_tc_opens_clean() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:sdt><w:sdtPr><w:alias w:val="company"/><w:id w:val="71"/></w:sdtPr><w:sdtContent><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Acme</w:t></w:r></w:p></w:tc></w:sdtContent></w:sdt></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.5.2.32 — a cell-level SDT (w:sdt child of w:tr wrapping one w:tc) \
         is a conformant CT_SdtCell arrangement; Word opens it without repair, so validate() \
         must report no errors",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:sdtContent>"),
        "ISO 29500-1 §17.5.2.33 — the cell-level sdtContent is structural markup stemma \
         preserves opaquely; a verbatim-preserving serializer must re-emit the sdtContent \
         wrapper. Got:\n{xml}"
    );
    assert_xml_ordered(
        &xml,
        &["<w:sdtContent>", "<w:tc>"],
        "ISO 29500-1 §17.5.2.33 (xmlRegex <w:sdtContent>\\s*<w:tc>) — the cell-level \
         sdtContent wraps exactly one w:tc; the wrapped cell must survive inside the \
         sdtContent, not be hoisted out of the SDT",
    );
}

#[test]
fn combobox_sdt_listitems_roundtrip_clean() {
    let body = r#"<w:p><w:sdt><w:sdtPr><w:alias w:val="Count"/><w:id w:val="606"/><w:comboBox><w:listItem w:displayText="Zero" w:value="0"/><w:listItem w:displayText="One" w:value="1"/></w:comboBox></w:sdtPr><w:sdtContent><w:r><w:t>Zero</w:t></w:r></w:sdtContent></w:sdt></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.5.2.5 — a comboBox SDT with listItem children is conformant; \
         Word opens it without repair, so validate() must report no errors",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:comboBox>"),
        "ISO 29500-1 §17.5.2.5 — the comboBox kind element is the control identity \
         (editable, distinct from dropDownList); verbatim SDT preservation must re-emit it \
         rather than dropping or substituting the kind. Got:\n{xml}"
    );
    assert!(
        xml.contains(r#"<w:listItem w:displayText="One" w:value="1"/>"#),
        "ISO 29500-1 §17.5.2.21 — each comboBox list item's displayText/value is control \
         state Word re-reads; dropping any item would corrupt the choice set, so verbatim \
         preservation must round-trip it unchanged. Got:\n{xml}"
    );
}

#[test]
fn nested_inline_sdt_inside_block_sdt_preserved_clean() {
    let body = r#"<w:sdt><w:sdtPr><w:tag w:val="outer"/><w:id w:val="700"/></w:sdtPr><w:sdtContent><w:p><w:sdt><w:sdtPr><w:tag w:val="inner"/><w:id w:val="701"/><w:text/></w:sdtPr><w:sdtContent><w:r><w:t>Nested</w:t></w:r></w:sdtContent></w:sdt></w:p></w:sdtContent></w:sdt><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.5.2.29/§17.5.2.31 — an inline SDT nested inside a block SDT's \
         paragraph is a conformant nesting; Word opens it without repair, so validate() must \
         report no errors",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"<w:tag w:val="outer"/>"#),
        "ISO 29500-1 §17.5.2.34 — the outer block SDT identity must survive; verbatim SDT \
         preservation must re-emit the outer tag. Got:\n{xml}"
    );
    assert!(
        xml.contains(r#"<w:tag w:val="inner"/>"#),
        "ISO 29500-1 §17.5.2.31 — the nested inline SDT is independent content-control \
         identity; the engine must not flatten or drop the inner control, so its tag must \
         survive verbatim. Got:\n{xml}"
    );
}

#[test]
fn sdt_end_pr_rpr_round_trips() {
    let body = r#"<w:p><w:sdt><w:sdtPr><w:alias w:val="name"/><w:id w:val="202"/><w:text/></w:sdtPr><w:sdtEndPr><w:rPr><w:b/><w:i/></w:rPr></w:sdtEndPr><w:sdtContent><w:r><w:t>value</w:t></w:r></w:sdtContent></w:sdt></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.5.2.37 — sdtEndPr is a conformant SDT property container; the \
         document must validate/open clean",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:sdtEndPr>"),
        "ISO 29500-1 §17.5.2.37 — sdtEndPr is untouched content carrying end-character \
         formatting; stemma's verbatim-preservation contract must re-emit it, not drop it. \
         Got:\n{xml}"
    );
    assert_xml_ordered(
        &xml,
        &[
            "<w:sdtEndPr>",
            "<w:rPr>",
            "<w:b/>",
            "<w:i/>",
            "</w:rPr>",
            "</w:sdtEndPr>",
        ],
        "ISO 29500-1 §17.5.2.28 (xmlRegex sdtEndPr>rPr>b>i) — the end-character rPr (b + i) \
         is meaningful formatting that must survive round-trip intact and in order inside \
         sdtEndPr",
    );
}

