#[test]
fn sdt_date_full_child_sequence_preserved() {
    let body = r#"<w:p><w:sdt><w:sdtPr><w:id w:val="4003"/><w:date w:fullDate="2006-01-01T06:30:00Z"><w:dateFormat w:val="M/d/yyyy"/><w:lid w:val="en-US"/><w:storeMappedDataAs w:val="dateTime"/><w:calendar w:val="gregorian"/></w:date></w:sdtPr><w:sdtContent><w:r><w:t>1/1/2006</w:t></w:r></w:sdtContent></w:sdt></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.5.2.7 / CT_SdtDate (wml.xsd) — the full CT_SdtDate sequence \
         (dateFormat, lid, storeMappedDataAs, calendar) in schema order with fullDate is \
         schema-valid, so Word opens it without repair",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"<w:storeMappedDataAs w:val="dateTime"/>"#),
        "ISO 29500-1 §17.5.2.40 — stemma reproduces the opaque w:date sub-tree verbatim; \
         the storeMappedDataAs child must not be dropped on round-trip. Got:\n{xml}"
    );
    assert!(
        xml.contains(r#"<w:calendar w:val="gregorian"/>"#),
        "ISO 29500-1 §17.5.2.3 — the calendar child (last in CT_SdtDate sequence) is \
         preserved verbatim; an engine modeling only dateFormat/lid would lose it. Got:\n{xml}"
    );
}

